#include <vector>
#include <string>
#include <stdexcept>

std::string ToModeLetters(const std::vector<std::string>& modeChanges, size_t malinelen) {
    std::string modeLetters;
    size_t currentLength = 0;

    for (const auto& change : modeChanges) {
        if (change.size() != 1 || (change[0] != '+' && change[0] != '-')) {
            throw std::invalid_argument("Invalid mode change");
        }

        if (currentLength >= malinelen) {
            throw std::out_of_range("Mode sequence length exceeded");
        }

        modeLetters += change[0];
        ++currentLength;
    }

    return modeLetters;
}
