// Function to validate and process printf format strings for file patterns
int validate_and_process_format_string(const char *format) {
    char processed_format[100]; // Buffer to store the processed format string
    int processed_len = 0; // Length of the processed format string

    // Iterate through each character in the input format string
    for (int i = 0; format[i] != '\0'; i++) {
        if (format[i] == '%') {
            // Check if the next character is a '%', which is a literal '%'
            if (format[i + 1] == '%') {
                // Append a single '%' to the processed format string
                processed_format[processed_len++] = '%';
                i++; // Skip the next character
            } else {
                // Check for integer specifiers
                if (format[i + 1] == '[') {
                    int num_start = i + 2;
                    int num_end = num_start;
                    // Find the end of the integer specifier
                    while (format[num_end] != ']' && format[num_end] != '\0') {
                        num_end++;
                    }
                    // If the integer specifier is valid
                    if (num_end > num_start) {
                        // Append the integer specifier to the processed format string
                        strncpy(processed_format + processed_len, format + num_start, num_end - num_start);
                        processed_len += num_end - num_start;
                        i = num_end; // Skip the integer specifier
                    } else {
                        // Invalid integer specifier
                        return -1;
                    }
                } else {
                    // Invalid format specifier
                    return -1;
                }
            }
        } else {
            // Append any other character to the processed format string
            processed_format[processed_len++] = format[i];
        }
    }
    // Null-terminate the processed format string
    processed_format[processed_len] = '\0';

    // Use snprintf to print the processed format string to a buffer
    char output[100];
    snprintf(output, sizeof(output), processed_format);

    // Print the output
    printf("Processed format string: %s\n", output);

    return 0;
}

