        fprintf(stderr, "Tile coordinates out of bounds\n");
        TIFFClose(tif);
        return;
    }

    if (tile_width <= 0 || tile_height <= 0) {
        fprintf(stderr, "Invalid tile dimensions\n");
        TIFFClose(tif);
        return;
    }

    uint32 tile_width_in_bytes = tile_width * TIFFGetField(tif, TIFFTAG_SAMPLESPERPIXEL) * TIFFGetField(tif, TIFFTAG_BITSPERSAMPLE) / 8;
    if (tile_width_in_bytes > MAX_BUFFER_SIZE) {
