// Define the structure for different types of expressions
typedef struct {
    int type;
    union {
        double number;
        char* string;
        struct {
            int size;
            struct Expression* list;
        } list;
    } data;
} Expression;

// Function to evaluate a number expression
double eval_number(Expression* expr) {
    return expr->data.number;
}

// Function to evaluate a string expression
double eval_string(Expression* expr) {
    // Assuming the string is a number
    return atof(expr->data.string);
}

// Function to evaluate a list expression
double eval_list(Expression* expr) {
    double sum = 0.0;
    for (int i = 0; i < expr->data.list.size; i++) {
        sum += eval_expression(expr->data.list.list[i]);
    }
    return sum;
}

// Function to safely evaluate expressions with recursion limited to 1000 levels
double eval7(Expression* expr, int depth) {
    if (depth > 1000) {
        fprintf(stderr, "Recursion depth exceeded\n");
        exit(EXIT_FAILURE);
    }
    switch (expr->type) {
        case EXPRESSION_NUMBER:
            return eval_number(expr);
        case EXPRESSION_STRING:
            return eval_string(expr);
        case EXPRESSION_LIST:
            return eval_list(expr);
        default:
            fprintf(stderr, "Unknown expression type\n");
            exit(EXIT_FAILURE);
    }
}

