#include <openssl/ssl.h>
#include <openssl/ocsp.h>
#include <openssl/x509.h>
#include <openssl/err.h>
#include <stdlib.h>
#include <string.h>

int ssl3_get_cert_status(SSL *ssl, unsigned char **out, size_t *outlen, int *outtype) {
    int ret = 0;
    unsigned char *ocsp_response = NULL;
    size_t ocsp_response_len = 0;

    // Validate message length
    if (ssl->packet_length < 3) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_SHORT_READ);
        return SSL_ERROR_SSL;
    }

    // Check message type
    if (ssl->packet[0] != 0x30) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_WRONG_MESSAGE_TYPE);
        return SSL_ERROR_SSL;
    }

    // Extract OCSP response length
    if (ssl->packet_length < 5) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_SHORT_READ);
        return SSL_ERROR_SSL;
    }
    ocsp_response_len = (ssl->packet[1] << 8) | ssl->packet[2];
    if (ocsp_response_len > ssl->packet_length - 3) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_BAD_OCSP_RESPONSE);
        return SSL_ERROR_SSL;
    }

    // Allocate memory for OCSP response
    ocsp_response = (unsigned char *)malloc(ocsp_response_len);
    if (ocsp_response == NULL) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, ERR_R_MALLOC_FAILURE);
        return SSL_ERROR_SSL;
    }

    // Copy OCSP response data
    memcpy(ocsp_response, ssl->packet + 3, ocsp_response_len);

    // Process OCSP response
    OCSP_RESPONSE *ocsp_resp = OCSP_response_new();
    if (ocsp_resp == NULL) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, ERR_R_MALLOC_FAILURE);
        free(ocsp_response);
        return SSL_ERROR_SSL;
    }

    if (!OCSP_response_parse(ocsp_resp, ocsp_response, ocsp_response_len)) {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_BAD_OCSP_RESPONSE);
        OCSP_RESPONSE_free(ocsp_resp);
        free(ocsp_response);
        return SSL_ERROR_SSL;
    }

    // Set output parameters
    *out = ocsp_response;
    *outlen = ocsp_response_len;
    *outtype = SSL_TLSEXT_STATUS_TYPE_OCSP;

    return SSL_SUCCESS;
}
