        return;
    }

    // Copy the original binary to the modified buffer
    memcpy(modified_binary, obj->bin, orig_size);

    // Replace class names in the modified binary
    char *ptr = modified_binary;
    while ((ptr = strstr(ptr, old_classname)) != NULL) {
        size_t old_len = strlen(old_classname);
        size_t new_len = strlen(new_classname);

        // Ensure there is enough space for the new class name
        if (ptr + old_len + new_len > modified_binary + orig_size) {
