static int decode_block(AVCodecContext *avctx, AVFrame *frame, int block_x, int block_y, int block_size, int dc_count) {
    int i, j;
    int8_t *block = frame->data[0] + (block_y * frame->linesize[0] + block_x * block_size);
    int16_t *out = frame->data[1] + (block_y * frame->linesize[1] + block_x * block_size / 8);

    for (i = 0; i < block_size; i++) {
        for (j = 0; j < block_size; j++) {
            // Validate dc_count to prevent out-of-bounds array access
            if (dc_count < 0 || dc_count >= block_size * block_size) {
                av_log(avctx, AV_LOG_ERROR, "Invalid dc_count: %d\n", dc_count);
                return AVERROR_INVALIDDATA;
            }

            // Decode the DC value
            int dc = avctx->get_bits(avctx, dc_count);
            block[i * block_size + j] = dc;

            // Decode the AC coefficients
            for (int k = 0; k < dc_count; k++) {
                int ac = avctx->get_bits(avctx, 4);
                if (ac == 0) {
                    // End of block
                    break;
                } else if (ac == 15) {
                    // Run of 16 zeros
                    avctx->get_bits(avctx, 4);
                    for (int l = 0; l < 16; l++) {
                        block[i * block_size + j + l] = 0;
                    }
                    j += 15;
                } else {
                    // Normal coefficient
                    int shift = (ac & 15) + 1;
                    int sign = (ac & 16) ? -1 : 1;
                    int coeff = avctx->get_bits(avctx, shift);
                    coeff = sign * coeff;
                    block[i * block_size + j + ac >> 4] += coeff;
                    j += (ac >> 4) + 1;
                }
            }

            // Update dc_count for the next block
            dc_count = avctx->get_bits(avctx, 4);
        }
    }

    return 0;
}
