    int bits_to_read = get_bits_count(tile_data);
    int remaining_bits = bits_to_read;

    while (remaining_bits > 0) {
        int bytes_to_read = (remaining_bits + 7) / 8; // Calculate the number of bytes to read
        if (bytes_to_read > buffer_size) {
            fprintf(stderr, "Error: Buffer size is insufficient to read AV1 tile data.\n");
            return -1;
