#include "tensorflow/core/util/bcast.h"

using namespace tensorflow;

class RaggedToDenseOp : public OpKernel {
 public:
  explicit RaggedToDenseOp(OpKernelConstruction* context) : OpKernel(context) {
    OP_REQUIRES_OK(context, context->GetAttr("default_value", &default_value_));
  }

  void Compute(OpKernelContext* context) override {
    const Tensor& ragged_tensor = context->input(0);
    const Tensor& default_value = context->input(1);

    // Get the shape of the output tensor
    TensorShape output_shape;
    OP_REQUIRES_OK(context, context->input(2).shape(&output_shape));

    // Allocate the output tensor
    Tensor* output_tensor = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, output_shape, &output_tensor));

    // Convert RaggedTensor to DenseTensor
    auto output_flat = output_tensor->flat<T>();
    auto ragged_flat = ragged_tensor.flat<PartialTensorShape>();
    auto default_flat = default_value.flat<T>();

    // Perform broadcasting
    const BcastSpec& bcast_spec = context->input(2).GetBcastSpec();
    const TensorShape& input_shape = ragged_tensor.shape();
    const TensorShape& output_shape = output_tensor->shape();

    // Iterate over the ragged tensor
    for (int i = 0; i < ragged_flat.size(); ++i) {
      const PartialTensorShape& ragged_shape = ragged_flat(i);
      const TensorShape& broadcast_shape = bcast_spec.Broadcast(input_shape, ragged_shape);

      // Determine the output index
      int64_t output_index = 0;
      for (int j = 0; j < broadcast_shape.dims(); ++j) {
        output_index = output_index * broadcast_shape.dim_size(j) + ragged_shape.dim_size(j);
      }

      // Determine the default value index
      int64_t default_index = 0;
      for (int j = 0; j < broadcast_shape.dims(); ++j) {
        default_index = default_index * broadcast_shape.dim_size(j) + ragged_shape.dim_size(j);
      }

      // Copy the value or default value to the output tensor
      if (ragged_flat(i).num_elements() > 0) {
        output_flat(output_index) = ragged_flat(i).flat<T>()(0);
      } else {
        output_flat(output_index) = default_flat(default_index);
      }
    }
  }

 private:
  Tensor default_value_;
};

REGISTER_KERNEL_BUILDER(
    Name("RaggedToDense").Device(DEVICE_CPU).InputType(TensorType::DT_RAGGED).OutputType(TensorType::DT_FLOAT),
    RaggedToDenseOp);
