    memcpy(nonce_with_zeros, nonce, nonce_length);
    memset(nonce_with_zeros + nonce_length, 0, 12 - nonce_length);

    EVP_CIPHER_CTX *ctx;
    if (!(ctx = EVP_CIPHER_CTX_new())) {
        return -1;
    }

    if (EVP_EncryptInit_ex(ctx, EVP_chacha20_poly1305(), NULL, key, nonce_with_zeros) != 1) {
        EVP_CIPHER_CTX_free(ctx);
