        EVP_CIPHER_CTX_free(ctx);
        return -1;
    }

    unsigned char tag[EVP_CIPHER_CTX_get_tag_length(ctx)];
    if (EVP_EncryptFinal_ex(ctx, out + outlen, &outlen) != 1) {
        EVP_CIPHER_CTX_free(ctx);
        return -1;
