    if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_GET_TAG, sizeof(tag), tag) != 1) {
        EVP_CIPHER_CTX_free(ctx);
        return -1;
    }

    EVP_CIPHER_CTX_free(ctx);

    // Append the tag to the output
    memcpy(out + outlen, tag, sizeof(tag));
