char *redisvFormatCommand(const char *format, va_list ap) {
    // Determine the maximum length of the formatted string
    va_list ap_copy;
    va_copy(ap_copy, ap);
    int length = vsnprintf(NULL, 0, format, ap_copy);
    va_end(ap_copy);

    // Allocate memory for the formatted string
    char *result = (char *)calloc(length + 1, sizeof(char));
    if (result == NULL) {
        fprintf(stderr, "Memory allocation failed for Redis command.\n");
        return NULL;
    }

    // Format the string and copy it to the allocated memory
    vsnprintf(result, length + 1, format, ap);

    return result;
}

int main() {
    // Example usage
    const char *command = "SET %s %d";
    char *formatted_command = redisvFormatCommand(command, "key", 12345);
    if (formatted_command != NULL) {
        printf("Formatted Redis command: %s\n", formatted_command);
        free(formatted_command);
    }

    return 0;
}
