json_object* json_read_array(const char* json_str, int* num_elements) {
    json_object* root = json_tokener_parse(json_str);
    if (!root || !json_object_is_array(root)) {
        if (root) json_object_put(root);
        *num_elements = 0;
        return NULL;
    }

    *num_elements = json_object_array_length(root);
    json_object* array = json_object_get_array(root);

    // Check if the array is empty
    if (*num_elements == 0) {
        json_object_put(root);
        return NULL;
    }

    return array;
}

